    17→pub struct TodoItemView {
    18→    pub id: String,
    19→    pub title: String,
    20→    pub is_completed: bool,
    21→}
    22→
    23→impl From<&TodoItem> for TodoItemView {
    24→    fn from(item: &TodoItem) -> Self {
    25→        Self {
    26→            id: item.id().as_uuid().to_string(),
    27→            title: item.title().as_str().to_string(),
