    39→
    40→pub async fn get_todos_page(
    41→    AuthenticatedUser(user_id): AuthenticatedUser,
    42→    State(pool): State<PgPool>,
    43→) -> Result<impl IntoResponse, TodosError> {
    44→    let todos = get_todos(&pool, &user_id)
    45→        .await
    46→        .map_err(TodosError::Unexpected)?;
    47→
    48→    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
    49→
    50→    let template = TodosTemplate {
    51→        todos: todo_views,
    52→        error_message: None,
    53→    };
    54→    Ok(Html(template.render()?))
    55→}
