    57→#[derive(serde::Deserialize)]
    58→pub struct AddTodoForm {
    59→    pub title: String,
    60→}
    61→
    62→pub async fn post_todo(
    63→    AuthenticatedUser(user_id): AuthenticatedUser,
    64→    State(pool): State<PgPool>,
    65→    Form(form): Form<AddTodoForm>,
    66→) -> Result<Response, TodosError> {
    67→    // Silently ignore empty/whitespace-only submissions per US-5
    68→    if form.title.trim().is_empty() {
    69→        return Ok(Redirect::to("/todos").into_response());
    70→    }
    71→
    72→    match add_todo(&pool, user_id.clone(), form.title).await {
    73→        Ok(_) => Ok(Redirect::to("/todos").into_response()),
    74→        Err(AddTodoError::InvalidTitle(title_err)) => {
    75→            let user_facing = match title_err {
    76→                crate::domain::TodoTitleError::Empty => {
    77→                    // Should not reach here due to empty check above, but handle gracefully
    78→                    return Ok(Redirect::to("/todos").into_response());
    79→                }
    80→                crate::domain::TodoTitleError::TooLong { max, .. } => {
    81→                    format!("That title is too long (max {max} characters)")
    82→                }
    83→            };
    84→
    85→            let todos = get_todos(&pool, &user_id)
    86→                .await
    87→                .map_err(TodosError::Unexpected)?;
    88→            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
    89→
    90→            let template = TodosTemplate {
    91→                todos: todo_views,
    92→                error_message: Some(user_facing),
    93→            };
    94→            let body = template.render().map_err(TodosError::Render)?;
    95→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
    96→        }
    97→        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    98→    }
    99→}
